VALUES
  ('optician-moex-00619', 'optician', 'optician-moex-111-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關人類眼睛感光細胞的敘述，下列何者正確？', '["感光細胞有兩種，分別為錐狀細胞及桿狀細胞，其數量比值約為 1：20", "錐狀細胞負責夜間視力或者在微暗照明的視力，分布於視網膜的中心部位", "感光細胞能將波長在 200-400nm的可見光轉變成神經訊息", "視網膜內的錐狀細胞至少有 3 種，分別為紅、綠和黃色的錐狀細胞，主要分布於黃斑部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "3f379e66bc49", "answer_pdf_sha1": "fb7847aae126", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
